import { CreatePlaidBankAccountResponse, useCreatePlaidBankAccount } from '@state/public/plaid';
import { toTitleCase } from '@utils/toTitleCase';
import { usePlaid } from '@utils/usePlaid/usePlaid';
import { useCallback, useEffect, useMemo, useState } from 'react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { Button } from '../../../Button';
import { CloseIcon } from '../../../icons';
import { Label } from '../../../Label';
import { Meta } from '../../../Meta';
import { FormSelectControl } from '../../../SelectControl';
import { BankAccountForm } from '../BankAccountForm';

type Props = {
  enableBusiness?: boolean;
  enablePersonal?: boolean;
  totalAmount?: number | null;
  verificationLimit?: number;
};

export const PlaidBankAccountForm = ({
  enableBusiness = true /** $200 */,
  enablePersonal = true,
  totalAmount,
  verificationLimit = 200 * 100,
}: Props) => {
  const { t } = useTranslation('finance', { keyPrefix: 'commitments.paymentMethodForm' });
  const { setValue, trigger } = useFormContext();
  const total = totalAmount || 0;
  const [showManualEntry, setShowManualEntry] = useState(total < verificationLimit);
  const [error, setError] = useState<string | null>(null);

  const [plaidBankAccount, setPlaidBankAccount] =
    useState<Nullable<CreatePlaidBankAccountResponse>>(null);

  const { createPlaidBankAccount, isLoading: isCreatingPlaidBankAccount } =
    useCreatePlaidBankAccount();

  const onLinkPlaid = useCallback(
    (publicToken) => {
      setError(null);

      createPlaidBankAccount({ publicToken })
        .then((bankAccount) => {
          setPlaidBankAccount(bankAccount);
          setValue('plaidBankAccountId', bankAccount.id);
          setValue('routingNumber', bankAccount.routingNumber);
          setValue('accountNumber', bankAccount.accountNumber);
          setValue('accountType', bankAccount.accountType);
          setValue('bankName', bankAccount.bankName);
        })
        .catch((err) => {
          console.error(err);

          setError(t('verificationFailure'));

          setShowManualEntry(true);
        });
    },
    [createPlaidBankAccount, setValue, t]
  );

  const {
    open: openPlaidLink,
    ready: isPlaidLinkReady,
    token: plaidLinkToken,
  } = usePlaid({ onSuccess: onLinkPlaid });

  const bankAccountHolderTypeOptions = useMemo(() => {
    const opts = [];

    if (enablePersonal) {
      opts.push({
        label: t('accountHolderType.personal'),
        value: 'personal',
      });
    }

    if (enableBusiness) {
      opts.push({
        label: t('accountHolderType.business'),
        value: 'business',
      });
    }

    return opts;
  }, [enableBusiness, enablePersonal, t]);

  useEffect(() => {
    setValue('plaidBankAccountId', plaidBankAccount?.id ?? null);

    if (plaidBankAccount?.id) {
      setValue('accountHolderType', 'personal');
      trigger();
    }
  }, [plaidBankAccount, setValue, trigger]);

  useEffect(() => {
    if (total >= verificationLimit) {
      setShowManualEntry(false);
      setValue('requiresVerification', true);
    } else {
      setShowManualEntry(true);
      setValue('requiresVerification', false);
    }
  }, [total, verificationLimit, setValue]);

  useEffect(() => {
    let timeout: ReturnType<typeof setTimeout>;
    if (error) {
      timeout = setTimeout(() => {
        setError(null);
      }, 6000);
    }

    return () => {
      clearTimeout(timeout);
    };
  }, [error]);

  const clearConnectedBankAccount = useCallback(() => setPlaidBankAccount(null), []);

  const closeError = useCallback(() => {
    setError(null);
  }, []);

  return (
    <>
      {error && (
        <div className="error pointer-events-auto m-2 w-auto min-w-[300px] max-w-[560px]">
          <CloseIcon className="ml-auto cursor-pointer" onClick={closeError} />
          {error}
          <Button onClick={closeError} variant="link">
            hide
          </Button>
        </div>
      )}
      {!showManualEntry ? (
        <div className="flex flex-col">
          {!plaidBankAccount ? (
            <Button
              className="w-full transition-opacity"
              isDisabled={!isPlaidLinkReady || !plaidLinkToken}
              isLoading={isCreatingPlaidBankAccount}
              onClick={() => openPlaidLink()}
              size="lg"
              variant="secondary"
            >
              {t('connectBank')}
            </Button>
          ) : null}
          {plaidBankAccount ? (
            <div className="mx-4 mb-4 flex flex-col gap-2 transition-opacity">
              <div className="flex">
                <Label className="text-neutral-700" variant="regular">
                  {plaidBankAccount.bankName}
                </Label>
                <CloseIcon
                  className="ml-auto w-[16px] cursor-pointer"
                  onClick={clearConnectedBankAccount}
                />
              </div>
              <Meta className="leading-[16px] text-neutral-500" variant="regular">
                {`${toTitleCase(
                  plaidBankAccount.accountType
                )} ****${plaidBankAccount.accountNumber.slice(-4)}`}
              </Meta>
              <FormSelectControl
                formControlProps={{ className: 'mt-4' }}
                isRequired
                label={t('accountHolderType.label')}
                name="accountHolderType"
                options={bankAccountHolderTypeOptions}
                placeholder="-"
              />
            </div>
          ) : null}
        </div>
      ) : null}
      {showManualEntry ? (
        <BankAccountForm enableBusiness={enableBusiness} enablePersonal={enablePersonal} />
      ) : null}
    </>
  );
};

